def factor_strategy(poly_terms):
    step1 = "1. Extract GCF"
    step2 = f"2. Count terms: {poly_terms}"
    if poly_terms == 2:
        step3 = "→ Check: difference of squares? a²−b²=(a+b)(a−b)"
    elif poly_terms == 3:
        step3 = "→ Trinomial: find p,q where p·q=c and p+q=b"
    else:
        step3 = "→ Group: factor pairs then factor common binomial"
    return [step1, step2, step3]
for s in factor_strategy(3): print(s)
